sql:
SELECT patient_id
FROM patient_symptoms
WHERE fever > 100;

SELECT patient_id, age, gender, cough, fever
FROM patient_symptoms
WHERE ACOSH(age) < 18 AND cough = 1 AND fever = 1;

external_knowledge:
- "Riding the storm" refers to patients experiencing severe symptoms;
- "Persistent cough and a fever that has crossed the scorching threshold" indicates cough and fever > 100 degrees;
- "When did these tempests touch down" refers to the dates when these symptoms first appeared.

sql:
SELECT age
FROM patient_symptoms
WHERE fever = (SELECT MIN(fever) FROM patient_symptoms WHERE fever > 0);

SELECT patient_id, address, age 
FROM patient_symptoms 
WHERE victims = 1 AND age = (SELECT MAX(age) FROM patient_symptoms WHERE victims = 1);

SELECT patient_id, ABS(fever - cough) AS symptom_difference
FROM patient_symptoms
WHERE symptom_severity = 'Severe';

SELECT (COUNT(patient_id) * 100.0 / (SELECT COUNT(*) FROM patient_symptoms)) AS hospitalization_percentage
FROM patient_symptoms
WHERE hospitalization_status = 1;

SELECT COUNT(*)
FROM patient_symptoms
WHERE fever >= (SELECT AVG(fever) FROM patient_symptoms);
